(function($){"use strict";var CONFIRM_MSG_BOTH="S'esborrarà el document del switch que desactiveu. Només es guardarà el document que es quedi actiu; el switch que quedi es comportarà com la resta (podreu canviar-lo de Públic a Restringit). Voleu continuar?";function showToast(message,isError){var $toast=$("#manageFilesToast");if(!$toast.length)$toast=$('<div id="manageFilesToast" class="position-fixed bottom-0 end-0 p-3" style="z-index: 1100"></div>').appendTo("body");var cls=isError?"alert-danger":"alert-success";var $alert=$('<div class="alert '+cls+' alert-dismissible fade show" role="alert">'+message+'<button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button></div>');$toast.append($alert);setTimeout(function(){$alert.fadeOut(function(){$(this).remove()})},4e3)}$(document).ready(function(){$(document).on("change",".visibility-switch",function(){var $row=$(this).closest(".visibility-row");var $input=$row.find("input.visibility-switch");var nowChecked=$input.prop("checked");var wasChecked=!nowChecked;var fileUrl=$row.data("file-url");var action=$row.data("action");var otherAction=$row.data("other-action");var hasBoth=$row.data("has-both")===true||$row.data("has-both")==="true";var otherRowId=$row.data("other-row-id");var url;var switchingAway=false;if(nowChecked)url=fileUrl+"/"+action;else switchingAway=true,url=fileUrl+"/"+(otherAction||(action==="hiddenToVisible"?"visibleToHidden":"hiddenToVisible"));if(hasBoth&&!window.confirm(CONFIRM_MSG_BOTH))return $input.prop("checked",wasChecked),void 0;$.ajax({url:url,type:"GET",dataType:"json",headers:{"X-Requested-With":"XMLHttpRequest"}}).done(function(data){if(data&&data.success){showToast(data.message||"Visibilitat del fitxer modificada correctament.",false);if(otherRowId&&otherRowId!=="None")$("#"+otherRowId).closest(".visibility-row").fadeOut(300,function(){$(this).remove()});if(switchingAway&&otherRowId&&otherRowId!=="None")$row.fadeOut(300,function(){$(this).remove()});else if(switchingAway){var $pill=$row.find(".visibility-switch-pill");var $label=$row.find(".visibility-switch-label");var newAction=otherAction||(action==="hiddenToVisible"?"visibleToHidden":"hiddenToVisible");var isNowPublic=newAction==="hiddenToVisible";$row.data("action",newAction);$row.data("other-action",action);$row.data("has-both",false);$row.data("other-row-id","");$pill.removeClass("visibility-switch-public visibility-switch-restringit").addClass(isNowPublic?"visibility-switch-public":"visibility-switch-restringit");$label.text(isNowPublic?"Públic":"Restringit");$input.prop("checked",true)}}else showToast((data&&data.message)||"Error en canviar la visibilitat.",true),$input.prop("checked",wasChecked)}).fail(function(xhr){var msg="Error en canviar la visibilitat.";try{var r=typeof xhr.responseText==="string"?JSON.parse(xhr.responseText):null;if(r&&r.message)msg=r.message}catch(err){}showToast(msg,true);$input.prop("checked",wasChecked)})})})})(jQuery);
